{
  "datasets": [
    {
      "name": "reg_summary",
      "displayName": "Deduplication Summary",
      "queryLines": [
        "SELECT\n",
        "  (SELECT COUNT(*) FROM primeins.silver.customers) as raw_records,\n",
        "  (SELECT COUNT(*) FROM primeins.gold.dim_customer) as unique_customers,\n",
        "  (SELECT COUNT(*) FROM primeins.silver.customers) - (SELECT COUNT(*) FROM primeins.gold.dim_customer) as duplicates_resolved,\n",
        "  ROUND(((SELECT COUNT(*) FROM primeins.silver.customers) - (SELECT COUNT(*) FROM primeins.gold.dim_customer)) * 100.0 / (SELECT COUNT(*) FROM primeins.silver.customers), 1) as dedup_rate_pct\n"
      ]
    },
    {
      "name": "reg_by_region",
      "displayName": "Customers by Region",
      "queryLines": [
        "SELECT region, COUNT(DISTINCT customer_id) as customers,\n",
        "  ROUND(COUNT(DISTINCT customer_id) * 100.0 / (SELECT COUNT(DISTINCT customer_id) FROM primeins.gold.dim_customer), 1) as pct\n",
        "FROM primeins.gold.dim_customer GROUP BY region ORDER BY customers DESC\n"
      ]
    },
    {
      "name": "reg_dq",
      "displayName": "Customer DQ Issues",
      "queryLines": [
        "SELECT d.rule_name, d.severity, d.affected_records,\n",
        "  ROUND(d.affected_ratio * 100, 1) as affected_pct, e.what_was_found\n",
        "FROM primeins.silver.dq_issues d\n",
        "LEFT JOIN primeins.gold.dq_explanation_report e ON d.table_name = e.table_name AND d.rule_name = e.rule_name\n",
        "WHERE d.table_name = 'customers'\n",
        "ORDER BY CASE d.severity WHEN 'critical' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END\n"
      ]
    },
    {
      "name": "reg_dupes",
      "displayName": "Cross-Regional Duplicates",
      "queryLines": [
        "SELECT customer_id, COUNT(*) as appearances, COLLECT_SET(_source_file) as source_files\n",
        "FROM primeins.silver.customers GROUP BY customer_id HAVING COUNT(*) > 1\n",
        "ORDER BY appearances DESC LIMIT 15\n"
      ]
    },
    {
      "name": "sla_overview",
      "displayName": "Claims Health",
      "queryLines": [
        "SELECT COUNT(*) as total_claims,\n",
        "  SUM(CASE WHEN is_rejected THEN 1 ELSE 0 END) as rejected,\n",
        "  SUM(CASE WHEN NOT is_rejected THEN 1 ELSE 0 END) as approved,\n",
        "  ROUND(SUM(CASE WHEN is_rejected THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) as rejection_rate_pct,\n",
        "  ROUND(SUM(total_claim_amount), 2) as total_value,\n",
        "  ROUND(AVG(total_claim_amount), 2) as avg_amount\n",
        "FROM primeins.gold.fact_claims\n"
      ]
    },
    {
      "name": "sla_region",
      "displayName": "Rejection by Region",
      "queryLines": [
        "SELECT region, total_claims, rejected_claims,\n",
        "  ROUND(rejection_rate_pct, 1) as rejection_rate_pct,\n",
        "  ROUND(total_claim_value, 2) as total_value\n",
        "FROM primeins.gold.mv_claims_by_region ORDER BY rejection_rate_pct DESC\n"
      ]
    },
    {
      "name": "sla_severity",
      "displayName": "Rejection by Severity",
      "queryLines": [
        "SELECT incident_severity, total_claims, rejected_claims,\n",
        "  ROUND(rejection_rate_pct, 1) as rejection_rate_pct,\n",
        "  ROUND(avg_claim_amount, 2) as avg_amount\n",
        "FROM primeins.gold.mv_claims_by_severity ORDER BY total_claims DESC\n"
      ]
    },
    {
      "name": "sla_policy",
      "displayName": "Rejection by Policy Tier",
      "queryLines": [
        "SELECT policy_csl as coverage_tier, total_claims, rejected_claims,\n",
        "  ROUND(rejection_rate_pct, 1) as rejection_rate_pct,\n",
        "  ROUND(avg_claim_amount, 2) as avg_amount\n",
        "FROM primeins.gold.mv_rejection_rate_by_policy ORDER BY rejection_rate_pct DESC\n"
      ]
    },
    {
      "name": "sla_high_value",
      "displayName": "High Value Rejected Claims",
      "queryLines": [
        "SELECT claim_id, policy_number, incident_severity, incident_type,\n",
        "  ROUND(total_claim_amount, 2) as amount,\n",
        "  incident_state\n",
        "FROM primeins.gold.fact_claims\n",
        "WHERE is_rejected = true AND total_claim_amount > 30000\n",
        "ORDER BY total_claim_amount DESC LIMIT 10\n"
      ]
    },
    {
      "name": "sla_anomaly",
      "displayName": "Flagged Claims",
      "queryLines": [
        "SELECT priority, COUNT(*) as flagged,\n",
        "  ROUND(AVG(anomaly_score), 1) as avg_score,\n",
        "  ROUND(AVG(total_claim_amount), 2) as avg_amount\n",
        "FROM primeins.gold.claim_anomaly_explanations GROUP BY priority ORDER BY priority\n"
      ]
    },
    {
      "name": "inv_overview",
      "displayName": "Inventory Health",
      "queryLines": [
        "SELECT COUNT(*) as total_listings,\n",
        "  SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) as sold,\n",
        "  SUM(CASE WHEN NOT is_sold THEN 1 ELSE 0 END) as unsold,\n",
        "  ROUND(SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) as sell_through_pct,\n",
        "  SUM(CASE WHEN NOT is_sold AND days_listed > 60 THEN 1 ELSE 0 END) as aging_60_plus,\n",
        "  ROUND(SUM(CASE WHEN NOT is_sold THEN original_selling_price ELSE 0 END), 0) as unsold_value\n",
        "FROM primeins.gold.fact_sales\n"
      ]
    },
    {
      "name": "inv_region",
      "displayName": "Sales by Region",
      "queryLines": [
        "SELECT region, COUNT(*) as listings,\n",
        "  SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) as sold,\n",
        "  SUM(CASE WHEN NOT is_sold THEN 1 ELSE 0 END) as unsold,\n",
        "  ROUND(SUM(CASE WHEN is_sold THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) as sell_through_pct\n",
        "FROM primeins.gold.fact_sales GROUP BY region ORDER BY sell_through_pct ASC\n"
      ]
    },
    {
      "name": "inv_redist",
      "displayName": "Redistribution Opportunities",
      "queryLines": [
        "WITH unsold AS (\n",
        "  SELECT dc.model, fs.region, COUNT(*) as unsold_count, AVG(fs.days_listed) as avg_days, AVG(fs.original_selling_price) as avg_price\n",
        "  FROM primeins.gold.fact_sales fs JOIN primeins.gold.dim_car dc ON fs.car_id = dc.car_id\n",
        "  WHERE fs.is_sold = false AND fs.days_listed > 60 GROUP BY dc.model, fs.region\n",
        "),\n",
        "sold_fast AS (\n",
        "  SELECT dc.model, fs.region, COUNT(*) as sold_count, AVG(fs.days_listed) as avg_days\n",
        "  FROM primeins.gold.fact_sales fs JOIN primeins.gold.dim_car dc ON fs.car_id = dc.car_id\n",
        "  WHERE fs.is_sold = true AND fs.days_listed < 30 GROUP BY dc.model, fs.region\n",
        ")\n",
        "SELECT u.model, u.region as stuck_region, u.unsold_count, CAST(u.avg_days AS INT) as days_sitting,\n",
        "  s.region as fast_region, s.sold_count, ROUND(u.unsold_count * u.avg_price, 0) as revenue_at_risk\n",
        "FROM unsold u JOIN sold_fast s ON u.model = s.model AND u.region != s.region\n",
        "ORDER BY revenue_at_risk DESC\n"
      ]
    },
    {
      "name": "inv_aging",
      "displayName": "Revenue at Risk by Region",
      "queryLines": [
        "SELECT region,\n",
        "  SUM(CASE WHEN NOT is_sold THEN 1 ELSE 0 END) as unsold_units,\n",
        "  ROUND(SUM(CASE WHEN NOT is_sold THEN original_selling_price ELSE 0 END), 0) as unsold_value,\n",
        "  SUM(CASE WHEN NOT is_sold AND days_listed > 90 THEN 1 ELSE 0 END) as critical_aging\n",
        "FROM primeins.gold.fact_sales GROUP BY region ORDER BY unsold_value DESC\n"
      ]
    },
    {
      "name": "risk_tiers",
      "displayName": "Risk Tiers",
      "queryLines": [
        "WITH cc AS (\n",
        "  SELECT dc.customer_id, dc.region, COUNT(fc.claim_id) as claims, ROUND(SUM(fc.total_claim_amount), 2) as total_value,\n",
        "    ROUND(SUM(CASE WHEN fc.is_rejected THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) as rej_rate\n",
        "  FROM primeins.gold.fact_claims fc JOIN primeins.gold.dim_policy dp ON fc.policy_number = dp.policy_number\n",
        "  JOIN primeins.gold.dim_customer dc ON dp.customer_id = dc.customer_id GROUP BY dc.customer_id, dc.region\n",
        ")\n",
        "SELECT CASE WHEN claims >= 3 OR total_value > 50000 THEN 'HIGH'\n",
        "  WHEN claims >= 2 OR total_value > 25000 THEN 'MEDIUM' ELSE 'LOW' END as risk_tier,\n",
        "  COUNT(*) as customers, ROUND(AVG(claims), 1) as avg_claims, ROUND(AVG(total_value), 2) as avg_value\n",
        "FROM cc GROUP BY 1 ORDER BY 1\n"
      ]
    },
    {
      "name": "risk_high",
      "displayName": "High Risk Customers",
      "queryLines": [
        "WITH cc AS (\n",
        "  SELECT dc.customer_id, dc.region, dc.state, COUNT(fc.claim_id) as claims,\n",
        "    ROUND(SUM(fc.total_claim_amount), 2) as total_value,\n",
        "    SUM(CASE WHEN fc.is_rejected THEN 1 ELSE 0 END) as rejected\n",
        "  FROM primeins.gold.fact_claims fc JOIN primeins.gold.dim_policy dp ON fc.policy_number = dp.policy_number\n",
        "  JOIN primeins.gold.dim_customer dc ON dp.customer_id = dc.customer_id\n",
        "  GROUP BY dc.customer_id, dc.region, dc.state\n",
        ")\n",
        "SELECT * FROM cc WHERE claims >= 3 OR total_value > 50000 ORDER BY total_value DESC\n"
      ]
    },
    {
      "name": "risk_region",
      "displayName": "Risk by Region",
      "queryLines": [
        "WITH cr AS (\n",
        "  SELECT dc.customer_id, dc.region, COUNT(fc.claim_id) as claims, SUM(fc.total_claim_amount) as tv,\n",
        "    CASE WHEN COUNT(fc.claim_id) >= 3 OR SUM(fc.total_claim_amount) > 50000 THEN 'HIGH'\n",
        "    WHEN COUNT(fc.claim_id) >= 2 OR SUM(fc.total_claim_amount) > 25000 THEN 'MEDIUM' ELSE 'LOW' END as tier\n",
        "  FROM primeins.gold.fact_claims fc JOIN primeins.gold.dim_policy dp ON fc.policy_number = dp.policy_number\n",
        "  JOIN primeins.gold.dim_customer dc ON dp.customer_id = dc.customer_id GROUP BY dc.customer_id, dc.region\n",
        ")\n",
        "SELECT region, tier, COUNT(*) as customers, ROUND(AVG(tv), 2) as avg_value\n",
        "FROM cr GROUP BY region, tier ORDER BY region, tier\n"
      ]
    },
    {
      "name": "risk_anomaly",
      "displayName": "Customers with Flagged Claims",
      "queryLines": [
        "SELECT dc.customer_id, dc.region, ca.claim_id, ca.anomaly_score, ca.priority,\n",
        "  ROUND(ca.total_claim_amount, 2) as amount, ca.triggered_rules\n",
        "FROM primeins.gold.claim_anomaly_explanations ca\n",
        "JOIN primeins.gold.fact_claims fc ON ca.claim_id = fc.claim_id\n",
        "JOIN primeins.gold.dim_policy dp ON fc.policy_number = dp.policy_number\n",
        "JOIN primeins.gold.dim_customer dc ON dp.customer_id = dc.customer_id\n",
        "WHERE ca.priority = 'HIGH' ORDER BY ca.anomaly_score DESC\n"
      ]
    }
  ],
